def self_discover_with_tools(task_instance: str, structure: dict, tools: list) -> str:
    """
    Stage 2 that handles tool use when the reasoning structure includes retrieval steps.
    Falls back to text completion for non-tool steps.
    """
    structure_text = json.dumps(structure, indent=2)
    messages = [
        {
            "role": "user",
            "content": (
                f"Use the reasoning structure below to solve the task. "
                f"Call tools when the step requires external information.\n\n"
                f"Structure:\n{structure_text}\n\n"
                f"Task:\n{task_instance}"
            ),
        }
    ]

    while True:
        response = client.messages.create(
            model=MODEL,
            max_tokens=1024,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if block.type == "text":
                    return block.text
            return ""

        # Handle tool calls
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
        messages.append({"role": "user", "content": tool_results})

def parse_json_robust(text: str) -> dict:
    text = text.strip()
    # Strip any leading ```json or ``` fence
    if text.startswith("```"):
        lines = text.split("\n")
        text = "\n".join(lines[1:])  # drop first line
        if text.endswith("```"):
            text = text[:-3]
    return json.loads(text.strip())
